package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonPrimitive;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

public class JsonTreeReaderTest {

  private JsonTreeReader reader;

  @BeforeEach
  public void setUp() throws Exception {
    // Create a JsonPrimitive boolean true element to pass to constructor
    JsonPrimitive truePrimitive = new JsonPrimitive(true);
    reader = new JsonTreeReader(truePrimitive);

    // Use reflection to set stack and stackSize because constructor sets them
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = (Object[]) stackField.get(reader);
    stack[0] = truePrimitive;
    stackField.set(reader, stack);

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(reader, 1);
  }

  @Test
  public void testNextBoolean_true() throws Exception {
    // nextBoolean expects JsonToken.BOOLEAN - so we mock expect to do nothing
    Method expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
    expectMethod.setAccessible(true);
    // Spy on reader to verify expect call and let it run normally
    JsonTreeReader spyReader = spy(reader);
    doNothing().when(spyReader).expect(JsonToken.BOOLEAN);

    // We need to set stack with a JsonPrimitive boolean true and stackSize>0
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = (Object[]) stackField.get(spyReader);
    JsonPrimitive boolPrimitive = new JsonPrimitive(true);
    stack[0] = boolPrimitive;
    stackField.set(spyReader, stack);

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(spyReader, 1);

    // Also set pathIndices to test increment
    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = new int[32];
    pathIndices[0] = 0;
    pathIndicesField.set(spyReader, pathIndices);

    // Call nextBoolean and verify result
    boolean result = spyReader.nextBoolean();
    assertTrue(result);

    // Verify pathIndices incremented
    int[] updatedPathIndices = (int[]) pathIndicesField.get(spyReader);
    assertEquals(1, updatedPathIndices[0]);

    // Verify expect called with JsonToken.BOOLEAN
    verify(spyReader).expect(JsonToken.BOOLEAN);
  }

  @Test
  public void testNextBoolean_false() throws Exception {
    // Spy to mock expect
    JsonTreeReader spyReader = spy(reader);
    doNothing().when(spyReader).expect(JsonToken.BOOLEAN);

    // Set stack with JsonPrimitive false
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = (Object[]) stackField.get(spyReader);
    JsonPrimitive boolPrimitive = new JsonPrimitive(false);
    stack[0] = boolPrimitive;
    stackField.set(spyReader, stack);

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(spyReader, 1);

    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = new int[32];
    pathIndices[0] = 5;
    pathIndicesField.set(spyReader, pathIndices);

    boolean result = spyReader.nextBoolean();
    assertFalse(result);

    int[] updatedPathIndices = (int[]) pathIndicesField.get(spyReader);
    assertEquals(6, updatedPathIndices[0]);

    verify(spyReader).expect(JsonToken.BOOLEAN);
  }

  @Test
  public void testNextBoolean_stackSizeZero_noPathIndexIncrement() throws Exception {
    JsonTreeReader spyReader = spy(reader);
    doNothing().when(spyReader).expect(JsonToken.BOOLEAN);

    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = (Object[]) stackField.get(spyReader);
    JsonPrimitive boolPrimitive = new JsonPrimitive(true);
    stack[0] = boolPrimitive;
    stackField.set(spyReader, stack);

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(spyReader, 0);

    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = new int[32];
    pathIndices[0] = 10;
    pathIndicesField.set(spyReader, pathIndices);

    boolean result = spyReader.nextBoolean();
    assertTrue(result);

    int[] updatedPathIndices = (int[]) pathIndicesField.get(spyReader);
    // pathIndices should not be incremented because stackSize == 0
    assertEquals(10, updatedPathIndices[0]);

    verify(spyReader).expect(JsonToken.BOOLEAN);
  }

  @Test
  public void testNextBoolean_popStackReturnsNonPrimitive_throwsClassCastException() throws Exception {
    JsonTreeReader spyReader = spy(reader);
    doNothing().when(spyReader).expect(JsonToken.BOOLEAN);

    // Set stack with an Object that is NOT a JsonPrimitive
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = (Object[]) stackField.get(spyReader);
    stack[0] = new Object();
    stackField.set(spyReader, stack);

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(spyReader, 1);

    assertThrows(ClassCastException.class, spyReader::nextBoolean);

    verify(spyReader).expect(JsonToken.BOOLEAN);
  }
}
